// UUID/ULID-Generator. type: uuid|ulid, count 1-50.
async function run(input) {
  var type = String((input && input.type) || 'uuid').toLowerCase();
  var count = Number((input && input.count) || 1);
  if (!(count >= 1)) count = 1;
  if (count > 50) count = 50;
  count = Math.floor(count);
  function uuidv4() {
    if (crypto && typeof crypto.randomUUID === 'function') return crypto.randomUUID();
    var b = new Uint8Array(16);
    crypto.getRandomValues(b);
    b[6] = (b[6] & 0x0f) | 0x40;
    b[8] = (b[8] & 0x3f) | 0x80;
    var hex = Array.prototype.map.call(b, function (x) { return x.toString(16).padStart(2, '0'); }).join('');
    return hex.slice(0, 8) + '-' + hex.slice(8, 12) + '-' + hex.slice(12, 16) + '-' + hex.slice(16, 20) + '-' + hex.slice(20);
  }
  var ENC = '0123456789ABCDEFGHJKMNPQRSTVWXYZ';
  function ulid() {
    var time = Date.now();
    var timeChars = '';
    for (var i = 9; i >= 0; i--) { timeChars = ENC[time % 32] + timeChars; time = Math.floor(time / 32); }
    var rand = new Uint8Array(16);
    crypto.getRandomValues(rand);
    var randChars = '';
    for (var j = 0; j < 16; j++) randChars += ENC[rand[j] % 32];
    return timeChars + randChars;
  }
  var ids = [];
  for (var k = 0; k < count; k++) ids.push(type === 'ulid' ? ulid() : uuidv4());
  return { type: type === 'ulid' ? 'ulid' : 'uuid', anzahl: ids.length, ids: ids };
}
